/**
 * Detect Fail-Safe Runtime issue bodies / agent prompts in chat (Product B).
 * Used by Cursor rules and tests — mirrors CI fail-safe trigger heuristics.
 */

export const RUNTIME_PROMPT_MARKERS = [
  "## Fail-Safe Runtime report",
  "Generated by Fail-Safe Runtime (Product B)",
  "[fail-safe-runtime]",
  "### Agent prompt",
];

/**
 * True when text looks like a Runtime report or issue body agents should fix.
 * @param {string} text
 */
export function isRuntimeFailSafePrompt(text) {
  const haystack = String(text || "");
  if (!haystack.trim()) return false;
  if (RUNTIME_PROMPT_MARKERS.some((marker) => haystack.includes(marker))) {
    return true;
  }
  return /cursor\/runtime-fail-\d{8}-/i.test(haystack);
}
